-- ════════════════════════════════════════════════════════════════════════
--  بذور بيانات أوامر الشراء — مُرحَّلة من ملف الإكسل (53 أمرًا حقيقيًا)
--  تُنفَّذ بعد db/purchase-orders.sql في Supabase → SQL Editor.
-- ════════════════════════════════════════════════════════════════════════
ON CONFLICT (po_number) DO UPDATE SET
  issue_date=EXCLUDED.issue_date, sector=EXCLUDED.sector, project=EXCLUDED.project,
  supplier=EXCLUDED.supplier, subtotal=EXCLUDED.subtotal, vat=EXCLUDED.vat, total=EXCLUDED.total,
  officer=EXCLUDED.officer, payment_method=EXCLUDED.payment_method, priority=EXCLUDED.priority,
  expected_delivery=EXCLUDED.expected_delivery, actual_delivery=EXCLUDED.actual_delivery,
  status=EXCLUDED.status, days_delayed=EXCLUDED.days_delayed, delay_reason=EXCLUDED.delay_reason,
  notes=EXCLUDED.notes, category=EXCLUDED.category, lead_time_days=EXCLUDED.lead_time_days,
  updated_at=now();
